CREATE TABLE IF NOT EXISTS appointments (id TEXT PRIMARY KEY,folio TEXT UNIQUE NOT NULL,service_id TEXT NOT NULL,service_name TEXT NOT NULL,date TEXT NOT NULL,start_at TEXT UNIQUE NOT NULL,end_at TEXT NOT NULL,name TEXT NOT NULL,email TEXT NOT NULL,phone TEXT NOT NULL,age INTEGER,address TEXT,city TEXT,postal_code TEXT,height INTEGER,reason TEXT,status TEXT NOT NULL,payment_option TEXT,amount_due REAL,amount_paid REAL DEFAULT 0,payment_id TEXT,payment_status TEXT,hold_until TEXT,calendar_event_id TEXT,created_at TEXT NOT NULL,updated_at TEXT);CREATE INDEX IF NOT EXISTS idx_appointments_date ON appointments(date,status);CREATE TABLE IF NOT EXISTS form_submissions (id TEXT PRIMARY KEY,folio TEXT UNIQUE NOT NULL,type TEXT NOT NULL,name TEXT NOT NULL,email TEXT,phone TEXT,payload TEXT NOT NULL,created_at TEXT NOT NULL);